# Category: saml_signature_wrapping

from flask import Flask, request, redirect, session
from flask_saml import SamlConfig, SamlResponse
from xml.etree import ElementTree as ET

app = Flask(__name__)

# Configure SAML SP
saml_config = SamlConfig()
saml_config.SP_ENTITY_ID = "your_sp_entity_id"
saml_config.SP_PRIVATE_KEY = "your_sp_private_key"
saml_config.SP_PUBLIC_CERT = "your_sp_public_cert"
saml_config.idp_entity_id = "your_idp_entity_id"
saml_config.SAML_VERSION = "2.0"

@app.route("/login")
def login():
    return redirect(saml_config.login_url)

@app.route("/callback", methods=["POST"])
def callback():
    saml_response = SamlResponse(request.form.get("SAMLResponse"))
    saml_response.validate(saml_config)

    xml_response = saml_response.xml()
    root = ET.fromstring(xml_response)

    # Extract user attributes from Assertion element
    assertion = root.find("saml:Assertion")
    attributes = assertion.findall("saml:AttributeStatement/saml:Attribute")

    # Create user session with extracted attributes
    session["username"] = assertion.findtext("saml:Subject/saml:NameID")
    for attribute in attributes:
        session[attribute.get("Name")] = attribute.findtext("saml:AttributeValue")

    return redirect("/protected")

@app.route("/protected")
def protected():
    if "username" in session:
        return f"Welcome, {session['username']}"
    else:
        return redirect("/login")

if __name__ == "__main__":
    app.run(debug=True)